const context: Context = {
	clockTolerance: 0,
	lang: 'en-US',
	subtle: crypto.subtle,
	trustedCertificates: [],
};

const httpClient = defaultHttpClient;

describe("The MsoMdocParser", () => {


	it("should parse a Base64-URL-encoded IssuerSigned object in mso_mdoc format", async () => {
		const parser = MsoMdocParser({ httpClient, context });

		const parsedIssuerSigned = await parser.parse({ rawCredential: issuerSignedB64U });

		assert(parsedIssuerSigned.success);
		assert(parsedIssuerSigned.value.metadata.credential.format === VerifiableCredentialFormat.MSO_MDOC);
		assert(parsedIssuerSigned.value.metadata.credential.doctype === "eu.europa.ec.eudi.pid.1");
		assert(parsedIssuerSigned.value.validityInfo.signed?.toISOString() === new Date("2025-02-18T14:12:04.000Z").toISOString());
		assert(parsedIssuerSigned.value.validityInfo.validUntil?.toISOString() === new Date("2025-03-04T14:12:04.000Z").toISOString());

		const nameSpace = parsedIssuerSigned.value.signedClaims["eu.europa.ec.eudi.pid.1"] as Record<string, unknown>;
		assert(nameSpace?.["family_name"] === "MUSTERMANN");
		assert(nameSpace?.["given_name"] === "ERIKA");
		assert((nameSpace?.["birth_date"] as Date).toISOString() === new Date("1964-08-12T00:00:00.000Z").toISOString());

	});

	it("should successfully parse a Base64-URL-encoded DeviceResponse in mso_mdoc format", async () => {
		const parser = MsoMdocParser({ httpClient, context });

		const parsedDeviceResponse = await parser.parse({ rawCredential: deviceResponseB64U });
		assert(parsedDeviceResponse.success);
		assert(parsedDeviceResponse.value.metadata.credential.format === VerifiableCredentialFormat.MSO_MDOC);
		assert(parsedDeviceResponse.value.metadata.credential.doctype === "eu.europa.ec.eudi.pid.1");

		const nameSpace = parsedDeviceResponse.value.signedClaims["eu.europa.ec.eudi.pid.1"] as Record<string, unknown>;
		assert(nameSpace?.["family_name"] === "MUSTERMANN");
		assert(nameSpace?.["given_name"] === "ERIKA");
		assert((nameSpace?.["birth_date"] as Date).toISOString() === new Date("1964-08-12T00:00:00.000Z").toISOString());

	})

	it("should successfully parse a Base64-URL-encoded DeviceResponse in eudiw Pid mso_mdoc format", async () => {
		const parser = MsoMdocParser({ httpClient, context });

		const parsedDeviceResponse = await parser.parse({
			rawCredential: eudiwPidMdoc,
			credentialIssuer: {
				credentialConfigurationId: 'eu.europa.ec.eudi.pid_mso_mdoc',
				credentialIssuerIdentifier: 'https://issuer-backend.eudiw.dev'
			}
		});
		assert(parsedDeviceResponse.success);
		assert(parsedDeviceResponse.value.metadata.credential.format === VerifiableCredentialFormat.MSO_MDOC);
		assert(parsedDeviceResponse.value.metadata.credential.doctype === "eu.europa.ec.eudi.pid.1");

		const nameSpace = parsedDeviceResponse.value.signedClaims["eu.europa.ec.eudi.pid.1"] as Record<string, unknown>;

		assert(nameSpace?.["family_name"] === "Neal");
		assert(nameSpace?.["given_name"] === "Tyler");

		//@ts-ignore
		expect(parsedDeviceResponse.value.metadata.credential.TypeMetadata.claims.some(
			w => JSON.stringify(w.path) === JSON.stringify(['eu.europa.ec.eudi.pid.1', 'family_name'])
		)
		).toBe(true);

	})

	it("should successfully parse a Base64-URL-encoded DeviceResponse in eudiw mdl mso_mdoc format", async () => {
		const parser = MsoMdocParser({ httpClient, context });

		const parsedDeviceResponse = await parser.parse({
			rawCredential: eudiwMdlMdoc,
			credentialIssuer: {
				credentialConfigurationId: 'org.iso.18013.5.1.mDL',
				credentialIssuerIdentifier: 'https://issuer-backend.eudiw.dev'
			}
		});
		assert(parsedDeviceResponse.success);
		assert(parsedDeviceResponse.value.metadata.credential.format === VerifiableCredentialFormat.MSO_MDOC);
		assert(parsedDeviceResponse.value.metadata.credential.doctype === "org.iso.18013.5.1.mDL");

		const nameSpace = parsedDeviceResponse.value.signedClaims["org.iso.18013.5.1"] as Record<string, unknown>;
		assert(nameSpace?.["family_name"] === "Georgiou");
		assert(nameSpace?.["given_name"] === "Georgios");

		//@ts-ignore
		expect(parsedDeviceResponse.value.metadata.credential.TypeMetadata.claims.some(
			w => JSON.stringify(w.path) === JSON.stringify(['org.iso.18013.5.1', 'family_name'])
		)
		).toBe(true);

	})

	it("should parse an OWF-issued IssuerSigned mdoc credential", async () => {
		const parser = MsoMdocParser({ httpClient, context });

		const parsedOwf = await parser.parse({ rawCredential: owfIssuedCredential });
		assert(parsedOwf.success);
		assert(parsedOwf.value.metadata.credential.format === VerifiableCredentialFormat.MSO_MDOC);
		assert(parsedOwf.value.metadata.credential.doctype === "eu.europa.ec.eudi.pid.1");

		const nameSpace = parsedOwf.value.signedClaims["eu.europa.ec.eudi.pid.1"] as Record<string, unknown>;
		assert(nameSpace?.["family_name"] === "Doe");
		assert(nameSpace?.["given_name"] === "John");
	})
})
